        "front": "Object-Oriented Programming (OOP)",
        "back": "A programming paradigm based on the concept of objects."
      },
      {
        "front": "Encapsulation",
        "back": "The bundling of data and methods that operate on the data within a single unit (class)."
      },
      {
        "front": "Abstraction",
        "back": "The concept of hiding complex implementation details and showing only the essential features of an object."
      },
      {
        "front": "Inheritance",
        "back": "A mechanism where a new class can inherit properties and behavior from an existing class."
      }
    ]
  }
